 20→func TestExportCSV_InvalidFiltersJSON(t *testing.T) {
 21→	t.Parallel()
 22→	reg := search.NewRegistry()
 23→	h := handler.ExportCSV(nil, reg, 500)
 24→
 25→	u := "/api/export/csv?filters=" + url.QueryEscape("not valid json")
 26→	w := httptest.NewRecorder()
 27→	r := httptest.NewRequest(http.MethodGet, u, nil)
 28→	h(w, r)
 29→
 30→	if w.Code != http.StatusBadRequest {
 31→		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
 32→	}
 33→
 34→	var body map[string]string
 35→	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 36→		t.Fatalf("decode body: %v", err)
 37→	}
 38→	if body["error"] == "" {
 39→		t.Error("expected non-empty error message")
 40→	}
 41→}
