103→// restrictedTestRegistry returns a registry with a single restricted enum field.
104→func restrictedTestRegistry() *search.Registry {
105→	f := search.NewTestSingleEnumField("secret_field", search.SearchabilityRestricted, []search.EnumOption{
106→		{Value: "a", Label: "A"},
107→		{Value: "b", Label: "B"},
108→	})
109→	return search.NewRegistryFromFields([]search.Field{f})
110→}
