112→func TestExportCSV_RestrictedField_Anonymous(t *testing.T) {
113→	t.Parallel()
114→	reg := restrictedTestRegistry()
115→	h := handler.ExportCSV(nil, reg, 500)
116→
117→	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
118→	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
119→	w := httptest.NewRecorder()
120→	r := httptest.NewRequest(http.MethodGet, u, nil)
121→	// No auth claims in context — anonymous request.
122→	h(w, r)
123→
124→	if w.Code != http.StatusBadRequest {
125→		t.Fatalf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
126→	}
127→
128→	var body struct {
129→		Errors []struct {
130→			Field   string `json:"field"`
131→			Message string `json:"message"`
132→		} `json:"errors"`
133→	}
134→	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
135→		t.Fatalf("decode body: %v", err)
136→	}
137→	if len(body.Errors) == 0 {
138→		t.Fatal("expected validation errors for restricted field")
139→	}
140→	found := false
141→	for _, e := range body.Errors {
142→		if e.Field == "secret_field" && strings.Contains(e.Message, "authentication") {
143→			found = true
144→			break
145→		}
146→	}
147→	if !found {
148→		t.Errorf("expected auth-required error for secret_field, got: %+v", body.Errors)
149→	}
150→}
