152→func TestExportCSV_RestrictedField_Authenticated(t *testing.T) {
153→	t.Parallel()
154→	reg := restrictedTestRegistry()
155→	h := handler.ExportCSV(nil, reg, 100)
156→
157→	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
158→	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
159→	w := httptest.NewRecorder()
160→	r := httptest.NewRequest(http.MethodGet, u, nil)
161→
162→	// Inject auth claims into context — authenticated request.
163→	ctx := auth.SetClaims(r.Context(), &auth.Claims{})
164→	r = r.WithContext(ctx)
165→
166→	// The handler will pass validation but panic on nil DB pool when
167→	// building the export query. A panic means validation succeeded,
168→	// which is the correct behaviour for an authenticated caller.
169→	defer func() {
170→		if r := recover(); r == nil {
171→			// No panic — handler wrote a response; check it wasn't a 400.
172→			if w.Code == http.StatusBadRequest {
173→				t.Fatalf("authenticated request should not be rejected; got 400 with body: %s", w.Body.String())
174→			}
175→		}
176→		// Panic from nil pool is expected — validation passed.
177→	}()
178→	h(w, r)
179→}
