 23→func TestGetSearchFields(t *testing.T) {
 24→	t.Parallel()
 25→	registry := search.NewRegistry()
 26→	handler := makeFieldsHandler(registry)
 27→
 28→	result, _, err := handler(context.Background(), nil, fieldsInput{})
 29→	if err != nil {
 30→		t.Fatalf("unexpected error: %v", err)
 31→	}
 32→	if result == nil {
 33→		t.Fatal("result is nil")
 34→	}
 35→	if len(result.Content) == 0 {
 36→		t.Fatal("result has no content")
 37→	}
 38→
 39→	text, ok := result.Content[0].(*mcp.TextContent)
 40→	if !ok {
 41→		t.Fatalf("expected TextContent, got %T", result.Content[0])
 42→	}
 43→
 44→	var descriptors []search.FieldDescriptor
 45→	if err := json.Unmarshal([]byte(text.Text), &descriptors); err != nil {
 46→		t.Fatalf("failed to unmarshal descriptors: %v", err)
 47→	}
 48→	if len(descriptors) == 0 {
 49→		t.Error("expected non-empty descriptors list")
 50→	}
 51→
 52→	// Verify that key fields are present.
 53→	names := make(map[string]bool)
 54→	for _, d := range descriptors {
 55→		names[d.Name] = true
 56→	}
 57→	for _, want := range []string{"name", "state", "enrollment"} {
 58→		if !names[want] {
 59→			t.Errorf("expected field %q in descriptors", want)
 60→		}
 61→	}
 62→}
