157→func TestSearchHandler_LimitExceedsMax(t *testing.T) {
158→	t.Parallel()
159→	registry := search.NewRegistry()
160→	handler := makeSearchHandler(nil, registry)
161→
162→	result, _, err := handler(context.Background(), nil, searchInput{
163→		Limit: 200,
164→	})
165→	if err != nil {
166→		t.Fatalf("unexpected Go error: %v", err)
167→	}
168→	if !result.IsError {
169→		t.Fatal("expected IsError=true for limit exceeding max")
170→	}
